const { AzureFunction, Context } = require('@azure/functions');
const childProcess = require('child_process');

const libreofficePath = '/path/to/libreoffice';
const tmpDir = '/tmp';

const convertDocument = async (context: Context) => {
  const reqBody = context.req.body;
  if (!reqBody.filename || !reqBody.outputFormat) {
    return { status: 400, body: 'Missing required parameters' };
  }

  const filename = reqBody.filename;
  const outputFormat = reqBody.outputFormat;

  // Validate input
  if (filename.match(/^[a-zA-Z0-9._-]+$/) === null) {
    return { status: 400, body: 'Invalid filename' };
  }
  if (!['pdf', 'docx', 'odt'].includes(outputFormat)) {
    return { status: 400, body: 'Unsupported output format' };
  }

  // Set up LibreOffice command
  const command = [
    libreofficePath,
    '--headless',
    '--convert-to',
    outputFormat,
    filename,
    '--outdir',
    tmpDir,
  ].join(' ');

  try {
    const result = await childProcess.execSync(command, { stdio: 'pipe' });
    return { status: 200, body: 'Document converted successfully' };
  } catch (error) {
    console.error(error);
    return { status: 500, body: 'Error converting document' };
  }
};

const httpTrigger = async (context: Context) => {
  const reqBody = context.req.body;
  if (!reqBody.filename || !reqBody.outputFormat) {
    return { status: 400, body: 'Missing required parameters' };
  }

  try {
    const result = await convertDocument(context);
    context.res = result;
  } catch (error) {
    console.error(error);
    context.log.error('Error handling request');
    context.res = { status: 500, body: 'Internal Server Error' };
  }
};

module.exports = httpTrigger;